INSERT INTO `shows` (`show_id`, `theatre_id`, `title`, `description`, `duration`, `age_rating`, `image_url`, `category`, `rating`, `room_name`) VALUES
	(1, 1, 'Οιδίπους Τύραννος', 'Η αριστουργηματική τραγωδία του Σοφοκλή έρχεται να καθηλώσει το κοινό σε μια σύγχρονη και συγκλονιστική σκηνοθετική προσέγγιση. Ένας φοβερός λοιμός μαστίζει την πόλη της Θήβας. Ο βασιλιάς Οιδίποδας, αποφασισμένος να σώσει τον λαό του, ξεκινά μια αγωνιώδη έρευνα για να ανακαλύψει τον δολοφόνο του προκατόχου του, Λάιου. Όσο όμως το νήμα ξετυλίγεται, η αλήθεια που έρχεται στο φως είναι πιο σκοτεινή και ανατριχιαστική από όσο θα μπορούσε ποτέ να φανταστεί. Ο τραγικός ήρωας έρχεται αντιμέτωπος με το ίδιο του το πεπρωμένο, εκπληρώνοντας τον πιο σκληρό χρησμό των θεών. Μια παράσταση για τη μοίρα, την αλαζονεία της εξουσίας και τα όρια της ανθρώπινης ύπαρξης', 110, '12+', 'https://www.ticketservices.gr/pictures/original/b_37877_or_afisa.jpg', 'Αρχαία Τραγωδία', '4.9', 'Σκηνή Νίκος Κούρκουλος'),
	(2, 2, 'Το Φάντασμα της Όπερας', 'Το θρυλικό μιούζικαλ που έχει μαγέψει εκατομμύρια θεατές σε όλο τον κόσμο, έρχεται σε μια φαντασμαγορική παραγωγή. Βαθιά κάτω από την Όπερα του Παρισιού, ένα παραμορφωμένο μουσικό ιδιοφυές περιφέρεται στους σκοτεινούς διαδρόμους. Σαγηνευμένος από το ταλέντο και την ομορφιά της νεαρής σοπράνο Κριστίν, το Φάντασμα θα κάνει τα πάντα για να την κάνει αστέρι της σκηνής, διεκδικώντας την αποκλειστική αγάπη της.\\n\\nΩστόσο, όταν ο παιδικός έρωτας της Κριστίν, ο Ραούλ, μπαίνει ξανά στη ζωή της, ένα επικίνδυνο ερωτικό τρίγωνο δημιουργείται. Πάθος, ζήλια και σκοτεινά μυστικά συνθέτουν μια επική ιστορία που συνοδεύεται από μαγευτική μουσική, εντυπωσιακά κοστούμια και εκπληκτικά σκηνικά.', 150, '10+', 'https://c.scdn.gr/images/sku_main_images/020275/20275933/xlarge_20210625165720_to_fantasma_tis_operas.jpeg', 'Μιούζικαλ', '4.8', 'Πλατεία Παλλάς'),
	(3, 3, 'Αντιγόνη', 'Η κορυφαία τραγωδία του Σοφοκλή ζωντανεύει, φέρνοντας στο προσκήνιο την αιώνια σύγκρουση ανάμεσα στον άγραφο ηθικό νόμο και την κρατική εξουσία. Μετά τον αιματηρό εμφύλιο της Θήβας, ο νέος άρχοντας Κρέοντας απαγορεύει αυστηρά την ταφή του "προδότη" Πολυνείκη. Η αδερφή του, Αντιγόνη, αψηφά τη διαταγή, επιλέγοντας να τιμήσει τον νεκρό αδερφό της, γνωρίζοντας καλά πως η πράξη της τιμωρείται με θάνατο.\\n\\nΗ παράσταση αναδεικνύει την αδιαπραγμάτευτη δύναμη της φωνής και το θάρρος της ατομικής ευθύνης απέναντι στην τυραννία. Μια συγκλονιστική ερμηνευτική εμπειρία που θέτει καίρια ερωτήματα για τη δημοκρατία, το δίκαιο και το προσωπικό χρέος, κρατώντας τον θεατή καθηλωμένο μέχρι το τραγικό τέλος.', 100, 'Όλες οι ηλικίες', 'https://www.ticketservices.gr/pictures/original/b_28324_or_afisa%20antigone-02.jpg', 'Αρχαία Τραγωδία', '4.7', 'Θέατρο Άννα Συνοδινού'),
	(4, 1, 'Άμλετ του Σαίξπηρ', 'Το κλασικό αριστούργημα του Ουίλλιαμ Σαίξπηρ παρουσιάζεται σε μια σύγχρονη, σκοτεινή και καθηλωτική σκηνοθεσία. Μια βαθιά εξερεύνηση της προδοσίας, της εκδίκησης και της ηθικής διαφθοράς. Με εντυπωσιακές ερμηνείες και ατμοσφαιρικά σκηνικά, αυτή η παράσταση υπόσχεται να κρατήσει το κοινό σε αγωνία μέχρι το τελευταίο λεπτό.', 140, '16+', 'https://www.zakynthos.gov.gr/media/2024/07/AMLET.png', 'Κλασικό Δράμα', '4.8', 'Κεντρική Σκηνή (Τσίλλερ)'),
	(5, 2, 'Chicago The Musical', 'Το θρυλικό μιούζικαλ του Μπρόντγουεϊ έρχεται με εκρηκτικά χορευτικά, αξεπέραστη τζαζ μουσική και αστραφτερή λάμψη. Μπείτε στον κόσμο του εγκλήματος, του πάθους και της δόξας στο Σικάγο της δεκαετίας του 1920. Μια φαντασμαγορική παραγωγή που συνδυάζει αιχμηρή σάτιρα, εντυπωσιακά κοστούμια και μια ζωντανή ορχήστρα που θα σας παρασύρει στον ρυθμό της.', 135, '12+', 'https://eratobooks.gr/wp-content/uploads/2025/07/7-16.jpg', 'Μιούζικαλ', '4.9', 'Πλατεία Παλλάς'),
	(6, 3, 'Λυσιστράτη του Αριστοφάνη', 'Η κορυφαία αντιπολεμική κωμωδία του Αριστοφάνη ζωντανεύει κάτω από τα αστέρια του καλοκαιρινού ουρανού. Μια ξεκαρδιστική παράσταση γεμάτη αιχμηρή σάτιρα, έξυπνους διαλόγους και αστείρευτο γέλιο. Όταν οι γυναίκες αναλαμβάνουν δράση για να σταματήσουν τον πόλεμο, τα αποτελέσματα είναι απρόβλεπτα και απολαυστικά!', 110, '14+', 'https://nikoskypourgos.com/wp-content/uploads/2020/07/1986-Lysistrata.jpg', 'Αρχαία Κωμωδία', '4.6', 'Θέατρο Μελίνα Μερκούρη'),
	(7, 12, 'Κάρμεν (Όπερα)', 'Το πάθος, η ελευθερία και η μοίρα συγκρούονται κάτω από το σεληνόφως του Ηρωδείου. Η εκρηκτική όπερα του Georges Bizet ζωντανεύει σε μια εντυπωσιακή παραγωγή, μεταφέροντας την κάψα της Σεβίλλης στην καρδιά της Αθήνας. Η ατίθαση τσιγγάνα Κάρμεν, μια γυναίκα που προτιμά να πεθάνει παρά να υποταχθεί, παρασύρει τον Δον Χοσέ σε έναν δίνη έρωτα και καταστροφής. Με τις πασίγνωστες μελωδίες της Habanera και του Toreador, η παράσταση αυτή υπόσχεται μια βραδιά γεμάτη ένταση, χρώμα και συγκλονιστικές ερμηνευτικές στιγμές που θα μείνουν χαραγμένες στη μνήμη σας.', 160, '12+', 'https://www.culturenow.gr/wp-content/uploads/2018/04/Ethniki_liriki_skini_Karmen_SITE_2_photo_Stefanos.jpg-300x300.jpg', 'Όπερα', '4.9', 'Άνω Κερκίδες Ηρωδείου'),
	(8, 6, 'Συναυλία: Ελληνικό Ροκ', 'Μια βραδιά γεμάτη ηλεκτρισμό, εκεί που το Σέιχ Σου συναντά την ένταση της ροκ σκηνής. Οι πιο εμβληματικές φωνές και τα συγκροτήματα που σημάδεψαν τις νύχτες μας, ενώνονται σε έναν μουσικό μαραθώνιο κάτω από τα αστέρια. Από τους ιστορικούς ύμνους των 80s μέχρι τον σύγχρονο εναλλακτικό ήχο, οι κιθάρες παίρνουν φωτιά και ο ρυθμός δεν σταματά. Ελάτε να γίνουμε μια μεγάλη παρέα και να τραγουδήσουμε για όλα αυτά που μας κάνουν να νιώθουμε ελεύθεροι. Το Θέατρο Δάσους θα δονηθεί από την ενέργεια του ελληνικού ροκ!', 180, 'Όλες', 'https://www.ticketservices.gr/pictures/original/b_52917_or_DSC08568-2.jpg', 'Συναυλία', '4.8', 'Κεντρικό Αμφιθέατρο Δάσους'),
	(9, 13, 'Ματωμένος Γάμος', 'Το ποιητικό αριστούργημα του Φεντερίκο Γκαρθία Λόρκα ζωντανεύει σε μια παράσταση γεμάτη πάθος, αίμα και πεπρωμένο. Στην άγονη γη της Ανδαλουσίας, ένας απαγορευμένος έρωτας ξυπνά παλιά μίση και οδηγεί σε μια αναπόφευκτη σύγκρουση. Η νύφη, ο γαμπρός και ο Λεονάρντο παγιδεύονται σε ένα παιχνίδι ζωής και θανάτου, κάτω από το παγερό βλέμμα της Σελήνης. Μια ωδή στον έρωτα που αψηφά τους κοινωνικούς κανόνες και στην τραγικότητα της ανθρώπινης φύσης. Μια εμπειρία που θα πλημμυρίσει τις αισθήσεις σας με μουσική, ποίηση και ένταση.', 110, '15+', 'https://www.n-t.gr/pictures/original/b_33770_or_matomenos_gamos_promo_jpeg_low_44_(2).jpg', 'Δράμα', '4.7', 'Σκηνή Ωμέγα ΔΘΠ'),
	(10, 13, 'Ο Εμποράκος', 'Η εμβληματική τραγωδία του σύγχρονου ανθρώπου, το έργο του Άρθουρ Μίλερ που καθόρισε τον 20ο αιώνα, ανεβαίνει στην Κεντρική Σκηνή του Πειραιά. Ο Γουίλι Λόμαν, ένας κουρασμένος πλασιέ, παλεύει να διατηρήσει τις αυταπάτες του για το αμερικανικό όνειρο, ενώ η οικογένειά του καταρρέει κάτω από το βάρος των μυστικών και των ανεκπλήρωτων προσδοκιών. Μια συγκλονιστική ανατομία της σχέσης πατέρα-γιου, της αποτυχίας και της αξιοπρέπειας. Ένα έργο που παραμένει τρομακτικά επίκαιρο, υπενθυμίζοντας μας πως η μεγαλύτερη τραγωδία είναι να σε ξεχάσει ο χρόνος.', 135, '12+', 'https://vrilissia.gr/wp-content/uploads/2025/11/thanatos_emporakou1.jpg', 'Δράμα', '4.6', 'Κεντρική Σκηνή ΔΘΠ'),
	(11, 14, 'Συμφωνική Ορχήστρα', 'Μια μεγαλειώδης μουσική εμπειρία στην καρδιά της Αθήνας. Η Συμφωνική Ορχήστρα παρουσιάζει ένα πρόγραμμα υψηλών απαιτήσεων, ταξιδεύοντάς μας από τον κλασικισμό του Μότσαρτ στον ρομαντισμό του Μπετόβεν. Υπό την καθοδήγηση διεθνούς φήμης μαέστρου, οι δεκάδες μουσικοί επί σκηνής δημιουργούν έναν ηχητικό όγκο που δονεί την Αίθουσα Χρήστος Λαμπράκης. Μια βραδιά αφιερωμένη στην τελειότητα της κλασικής μουσικής και τη δύναμη της συλλογικής ερμηνείας.', 120, 'Όλες', 'https://mousikasynola.ert.gr/wp-content/uploads/2023/10/NSO-Herodus-Atticus.jpg', 'Κλασική Μουσική', '5.0', 'Αίθουσα Ν. Σκαλκώτας'),
	(12, 1, 'Ρωμαίος και Ιουλιέτα', 'Η αθάνατη ιστορία του Ουίλλιαμ Σαίξπηρ, ο απόλυτος ύμνος στον έρωτα που αψηφά το μίσος και τον θάνατο. Δύο νέοι, παγιδευμένοι ανάμεσα σε δύο οικογένειες που τις χωρίζει μια άσβεστη έχθρα, αποφασίζουν να ζήσουν το πάθος τους μέχρι τέλους. Μια σύγχρονη προσέγγιση του κλασικού αριστουργήματος που αναδεικνύει την ένταση, την τραγικότητα και τη διαχρονική ομορφιά της πιο διάσημης ερωτικής ιστορίας όλων των εποχών. Μια παραγωγή που θα σας καθηλώσει με την αισθητική και τις ερμηνείες της.', 120, '12+', 'https://www.lifo.gr/sites/default/files/styles/max_1920x1920/public/articles/2023-03-31/romeo_and_juliet%20%289%29_0.jpg?itok=sba1B49B', 'Δράμα', '4.8', 'Κεντρική Σκηνή (Τσίλλερ)'),
	(13, 2, 'Mamma Mia!', 'Το απόλυτο feel-good μιούζικαλ που λάτρεψαν εκατομμύρια θεατές σε όλο τον κόσμο, μας ταξιδεύει κάτω από τον ήλιο του Αιγαίου. Με φόντο ένα ειδυλλιακό ελληνικό νησί, η ιστορία της Sophie ξετυλίγεται μέσα από τους αξέχαστους ρυθμούς των ABBA. Μια κόρη, μια μητέρα και τρεις πιθανοί μπαμπάδες συναντιούνται σε ένα σκηνικό γεμάτο ανατροπές, γέλιο και συγκίνηση. Το \'Mamma Mia!\' είναι μια γιορτή της ζωής και της αγάπης που θα σας κάνει να θέλετε να χορέψετε από το πρώτο λεπτό!', 150, 'Όλες οι ηλικίες', 'https://upload.wikimedia.org/wikipedia/en/c/c3/Mammamiaposter.jpg', 'Μιούζικαλ', '4.9', 'Πλατεία Παλλάς'),
	(14, 3, 'Μήδεια του Ευριπίδη', 'Η Μήδεια του Ευριπίδη αποτελεί την πιο συγκλονιστική σπουδή πάνω στην προδοσία, την εκδίκηση και τα αδιέξοδα του ανθρώπινου πάθους. Μια γυναίκα-σύμβολο, ξένη σε μια εχθρική χώρα, μετατρέπει τον πόνο της προδοσίας σε μια καταστροφική δύναμη που δεν γνωρίζει όρια. Όταν ο Ιάσονας την εγκαταλείπει, η Μήδεια αναμετράται με τη μοίρα και τα μητρικά της ένστικτα, οδηγούμενη στην πιο σκοτεινή πράξη που γνώρισε ποτέ το παγκόσμιο θέατρο. Μια παράσταση που θα σας κόψει την ανάσα.', 110, '16+', 'https://megalopoli.gov.gr/wp-content/uploads/2025/07/mideia-3-683x1024.jpg', 'Αρχαία Τραγωδία', '4.7', 'Θέατρο Μελίνα Μερκούρη'),
	(15, 6, 'Συναυλία: Έντεχνο', 'Οι πιο όμορφες μελωδίες κάτω από το φως του φεγγαριού. Μια βραδιά αφιερωμένη στην ποίηση του ελληνικού τραγουδιού, με σπουδαίους ερμηνευτές και δεξιοτέχνες μουσικούς. Από τον Χατζιδάκι και τον Θεοδωράκη μέχρι τους σύγχρονους δημιουργούς, το έντεχνο τραγούδι βρίσκει το ιδανικό του καταφύγιο μέσα στη φύση του Δάσους. Μια μυσταγωγική εμπειρία που ισορροπεί ανάμεσα στη νοσταλγία και την ελπίδα, προσφέροντας μια ανάσα πολιτισμού και βαθιάς συγκίνησης. Αφήστε τις μουσικές να σας ταξιδέψουν.', 160, 'Όλες οι ηλικίες', 'https://www.athinorama.gr/Content/ImagesDatabase/p/750x422/crop/both/f8/f8f2faf613574e21a5cd0f903dd3ebc4.jpg?quality=81&404=default&v=4', 'Συναυλία', '4.8', 'Μικρή Σκηνή Δάσους'),
	(16, 6, 'Stand Up Comedy Nights', 'Προσοχή: Κίνδυνος ακράτειας... από τα γέλια! Οι καλύτεροι stand-up comedians της χώρας συγκεντρώνονται στη Μικρή Σκηνή Δάσους για να ανατομήσουν με χειρουργική ακρίβεια (και πολύ θράσος) την ελληνική πραγματικότητα. Ιστορίες για την καθημερινότητα, τις σχέσεις, τα social media και όλα τα παράλογα που ζούμε, ειπωμένα με καταιγιστικό ρυθμό και ασταμάτητες ατάκες. Μια διαδραστική εμπειρία όπου κανείς δεν είναι ασφαλής στην πρώτη σειρά, αλλά όλοι φεύγουν με λιγότερα προβλήματα και περισσότερο κέφι. Η καλύτερη αποτοξίνωση από το άγχος της πόλης!', 100, '15+', 'https://images.unsplash.com/photo-1585699324551-f6c309eedeca?w=800&q=80', 'Κωμωδία', '4.6', 'Κεντρικό Αμφιθέατρο Δάσους'),
	(17, 12, 'Η Λίμνη των Κύκνων', 'Το απόλυτο παραμύθι του κλασικού χορού συναντά την ιστορική μεγαλοπρέπεια του Ωδείου Ηρώδου Αττικού. Η αθάνατη μουσική του Tchaikovsky και η αιθέρια κίνηση των κορυφαίων χορευτών συνθέτουν ένα σκηνικό ονείρου. Η πάλη ανάμεσα στο λευκό και το μαύρο κύκνο, η προδοσία και η λυτρωτική δύναμη της αγάπης ξετυλίγονται πάνω στα αρχαία μάρμαρα, προσφέροντας ένα θέαμα σπάνιας ομορφιάς και τεχνικής τελειότητας. Μια μυσταγωγική εμπειρία που αναδεικνύει την ποίηση του σώματος σε έναν από τους πιο ατμοσφαιρικούς χώρους του κόσμου.', 140, 'Όλες οι ηλικίες', 'https://www.musicity.gr/wp-content/uploads/2024/09/i-limni-ton-kyknon.webp', 'Μπαλέτο', '5.0', 'Άνω Κερκίδες Ηρωδείου'),
	(18, 12, 'Νόρμα (Όπερα)', 'Το κορυφαίο αριστούργημα του bel canto επιστρέφει εκεί που ο ήχος συναντά το θείο. Η Νόρμα του Vincenzo Bellini, η ιστορία της αρχιέρειας των Δρυιδών που διχάζεται ανάμεσα στο καθήκον προς την πατρίδα και τον απαγορευμένο έρωτα για έναν Ρωμαίο εχθρό, αποτελεί την επιτομή της δραματικής όπερας. Με την εμβληματική προσευχή \'Casta Diva\' να αντηχεί στον ιερό χώρο του Ηρωδείου, η παράσταση εξερευνά τα όρια της θυσίας και της ανθρώπινης ψυχής. Μια βραδιά υψηλής αισθητικής και βαθιάς συγκίνησης, αφιερωμένη στην απόλυτη δύναμη της φωνής και του δράματος.', 170, '12+', 'https://www.culturenow.gr/wp-content/uploads/2019/05/-%CE%9D%CF%8C%CF%81%CE%BC%CE%B1-%CE%97%CF%81%CF%8E%CE%B4%CE%B5%CE%B9%CE%BF_8489-%CF%86%CF%89%CF%84%CF%8C-%CE%94.-%CE%A3%CE%B1%CE%BA%CE%B1%CE%BB%CE%AC%CE%BA%CE%B7%CF%82-e1559815135226.jpg', 'Όπερα', '4.9', 'Κάτω Διάζωμα Ηρωδείου'),
	(19, 13, 'Ο Θείος Βάνιας', 'Η γοητεία της ρωσικής μελαγχολίας συναντά την απαράμιλλη γραφή του Αντόν Τσέχοφ. Σε ένα επαρχιακό κτήμα, οι ήρωες ζουν ανάμεσα σε χαμένες ευκαιρίες, ανεκπλήρωτους έρωτες και την αργή φθορά του χρόνου. Ο Θείος Βάνιας και ο γιατρός Άστροφ αναζητούν ένα νόημα σε μια ζωή που μοιάζει να τους προσπερνά, ισορροπώντας με δεξιοτεχνία ανάμεσα στο δράμα και το λεπτό χιούμορ. Μια παράσταση για τις ματαιώσεις της ύπαρξης αλλά και για την κρυφή ελπίδα ότι \'κάποτε θα αναπαυθούμε\'. Ένα μάθημα ανθρωπιάς και αλήθειας που θα σας αγγίξει βαθιά.', 130, '12+', 'https://www.dithepi.gr/pictures/b/b_26753_463904784_8576392812415007_3347744307018257194_n.jpg', 'Κλασικό Δράμα', '4.7', 'Σκηνή Ωμέγα ΔΘΠ'),
	(20, 14, 'Ρεσιτάλ Πιάνου', 'Η απόλυτη μοναξιά και η απόλυτη δεξιοτεχνία πάνω στα 88 πλήκτρα. Ένας βραβευμένος σολίστ αναμετράται με τα πιο απαιτητικά έργα των Σοπέν, Λιστ και Ραχμάνινοφ, σε μια βραδιά που αναδεικνύει τις απεριόριστες δυνατότητες του πιάνου. Από τους πιο λεπτούς ψιθύρους έως τις πιο εκρηκτικές κορυφώσεις, το ρεσιτάλ αυτό είναι μια εσωτερική διαδρομή που μετατρέπει τη σιωπή σε ποίηση. Μια μυσταγωγία για τους λάτρεις της μουσικής δωματίου.', 90, 'Όλες οι ηλικίες', 'https://www.megaron.gr/wp-content/uploads/2024/11/DSC_0546-630x740.jpg', 'Μουσική', '4.8', 'Αίθουσα Χρ. Λαμπράκης'),
	(21, 14, 'Όπερα του Δρόμου', 'Τι συμβαίνει όταν η κλασική παιδεία συναντά την ενέργεια του δρόμου; Η \'Όπερα του Δρόμου\' ανατρέπει τα δεδομένα, φέρνοντας τις μεγαλύτερες άριες του κόσμου σε μια σύγχρονη, αστική αισθητική. Με φρέσκιες ενορχηστρώσεις που περιλαμβάνουν τζαζ και ηλεκτρονικά στοιχεία, η παράσταση σπάει τα στερεότυπα και αποδεικνύει ότι η όπερα ανήκει σε όλους. Μια πρωτοποριακή παραγωγή που θα σας κάνει να δείτε το λυρικό θέατρο με μια εντελώς νέα ματιά.', 115, '12+', 'https://dynamic-media-cdn.tripadvisor.com/media/photo-o/32/2d/9a/0f/caption.jpg?w=1200&h=1200&s=1', 'Όπερα', '4.6', 'Αίθουσα Ν. Σκαλκώτας');
