INSERT INTO `theatres` (`theatre_id`, `name`, `location`, `description`, `image_url`) VALUES
	(1, 'Εθνικό Θέατρο', 'Αγίου Κωνσταντίνου 22, Αθήνα', 'Η κεντρική σκηνή του Εθνικού Θεάτρου.', 'https://www.n-t.gr/pictures/b/b_32877_national_theatre_of_greece-38.jpg'),
	(2, 'Θέατρο Παλλάς', 'Βουκουρεστίου 5, Αθήνα', 'Ιστορικό και πολυτελές θέατρο στο κέντρο της πόλης.', 'https://dynamic-media-cdn.tripadvisor.com/media/photo-o/01/7a/44/70/athens.jpg?w=400&h=200&s=1'),
	(3, 'Θέατρο Βράχων', 'Βύρωνας', 'Ανοιχτό θέατρο, ιδανικό για καλοκαιρινές παραστάσεις.', 'https://www.lifo.gr/sites/default/files/styles/max_1920x1920/public/articles/2023-06-29/braxwn.png?itok=J3JOZYKQ'),
	(6, 'Θέατρο Δάσους', 'Δάσος Σέιχ Σου, Θεσσαλονίκη', 'Ένα μαγευτικό ανοιχτό θέατρο μέσα στη φύση, ιδανικό για καλοκαιρινές παραστάσεις και αρχαίες τραγωδίες.', 'https://i.ytimg.com/vi/SgvOOo4vPuU/maxresdefault.jpg'),
	(12, 'Ωδείο Ηρώδου Αττικού (Ηρώδειο)', 'Διονυσίου Αρεοπαγίτου, Αθήνα', 'Το εμβληματικό αρχαίο ρωμαϊκό ωδείο στη σκιά της Ακρόπολης, παγκοσμίως γνωστό για τις μοναδικές παραστάσεις του Φεστιβάλ Αθηνών.', 'https://www.allovergreece.com/uploads/archaeological-sites/Herodion(02).jpg'),
	(13, 'Δημοτικό Θέατρο Πειραιά', 'Λεωφ. Ηρώων Πολυτεχνείου 32, Πειραιάς', 'Ένα πραγματικό αρχιτεκτονικό στολίδι νεοκλασικής ομορφιάς στο κέντρο του Πειραιά, από τα σημαντικότερα θέατρα της Ελλάδας.', 'https://static.euronews.com/articles/stories/04/65/83/86/1200x675_cmsv2_63acbb97-1d8e-5d73-9188-081ed8f1c0aa-4658386.jpg'),
	(14, 'Μέγαρο Μουσικής Αθηνών', 'Βασ. Σοφίας & Κόκκαλη 1, Αθήνα', 'Ένα από τα πιο σύγχρονα πολιτιστικά κέντρα διεθνώς, με εξαιρετική ακουστική και υπερσύγχρονες σκηνές.', 'https://www.megaron.gr/wp-content/uploads/2020/06/Christos-Lambrakis-Hall_c-%CE%9A%CE%B1%CF%81%CE%B1%CE%BC%CE%B1%CE%BD%CE%B9%CE%B1%CE%BD-1-site.jpg');
